using System;
using System.Diagnostics;
using System.IO;

public class PdfGenerator
{
    private const string WkHtmlToPdfPath = "wkhtmltopdf.exe";

    public void GeneratePdf(string htmlFilePath, string pdfOutputPath, string pageSize = "A4", string orientation = "Portrait")
    {
        var arguments = $"{htmlFilePath} {pdfOutputPath} --page-size={pageSize} --orientation={orientation}";

        // Ensure the path to wkhtmltopdf.exe is valid and exists
        if (!File.Exists(WkHtmlToPdfPath))
            throw new FileNotFoundException("wkhtmltopdf not found", WkHtmlToPdfPath);

        // Prevent command injection by properly escaping special characters in the input file path
        var escapedHtmlFilePath = EscapeSpecialCharacters(htmlFilePath);
        arguments = $"{escapedHtmlFilePath} {pdfOutputPath} --page-size={pageSize} --orientation={orientation}";

        // Use Process.Start to execute the wkhtmltopdf command
        var process = new Process
        {
            StartInfo = new ProcessStartInfo
            {
                FileName = WkHtmlToPdfPath,
                Arguments = arguments,
                RedirectStandardOutput = true,
                UseShellExecute = false,
                CreateNoWindow = true
            }
        };
        process.Start();
        process.WaitForExit();
    }

    private string EscapeSpecialCharacters(string input)
    {
        return input.Replace("\"", "\\\"");
    }
}